function [data, auxData, metaData, txtData, weights] = mydata_Drosophila_melanogaster
% file generated by prt_mydata

%% set metaData
metaData.phylum     = 'Arthropoda';
metaData.class      = 'Insecta';
metaData.order      = 'Diptera';
metaData.family     = 'Drosophilidae';
metaData.species    = 'Drosophila_melanogaster';
metaData.species_en = 'fruit fly';

metaData.ecoCode.climate = {'A','B','C'};      % tropical–subtropical–temperate; cosmopolitan distribution
metaData.ecoCode.ecozone = {'TH','TN','TPa'};  % tropical humid, temperate nemoral, anthropogenic/peri-urban
metaData.ecoCode.habitat = {'0eTer','eiTi'};   % terrestrial; human-associated terrestrial habitats
metaData.ecoCode.embryo  = {'Th'};             % terrestrial, lecithotrophic eggs
metaData.ecoCode.migrate = {};                 % no migratory behaviour
metaData.ecoCode.food    = {'bjD','0iHs'};     % detritus/yeast substrates; human-associated food sources
metaData.ecoCode.gender  = {'D'};              % dioecious
metaData.ecoCode.reprod  = {'O'};              % oviparous

metaData.T_typical  = C2K(25); % K, body temp

metaData.data_0     = {'E0','ab','t1','t2','tj','Lb','L1','L2','Lj','ae','Wd_e','R','am'};
metaData.data_1     = {'tWw','tWd_f','tWd_m','tWd','tS','tSC','tL','tS_f','tR_f'};

metaData.COMPLETE   = 1; % using criteria of LikaKear2011

metaData.author     = {'Panagiotis Sakagiannis'};
metaData.date_subm  = [2026 1 1];
metaData.email      = {'p.sakagiannis@uni-koeln.de'};
metaData.address    = {'University Cologne'};

metaData.curator    = {'Dina Lika'};
metaData.email_cur  = {'lika@uoc.gr'};
metaData.date_acc   = [0 0 29];

%=============================================================
% Drosophila melanogaster vs Bactrocera oleae (Comparative Summary)
%=============================================================
%
% Phylogeny:
%   - Both Diptera (Brachycera); diverged ~70 MYA.
%   - Closer to each other than either is to Aedes aegypti (~150 MYA).
%
% Ovary Maturation:
%   - Immature at eclosion in both.
%   - D. melanogaster matures in 2–3 d (yeast diet);
%     B. oleae in 6–10 d (protein diet).
%
% Diet:
%   - Both require sugars for energy and proteins for oogenesis.
%   - Drosophila uses yeast; Bactrocera uses natural protein sources.
%
% Sexual Dimorphism:
%   - In both, females are larger and have greater abdominal volume.
%   - Drosophila males show sex combs;
%
% Development & Lifespan:
%   - Drosophila: egg→adult ~10 d; lifespan 30–50 d @25°C.
%   - Bactrocera: egg→adult ~30–40 d; lifespan 1–2 mo.
%
% Summary:
%   - Evolutionarily close fruit flies with shared endocrine and
%     reproductive mechanisms; Drosophila is faster, more fecund, and
%     saprophytic, Bactrocera slower, less fecund, and host-specific.
%=============================================================
%% Conflicts :

% tWw in Church1966 and Testa2013
% 

%% SUMMARY OF DATA IN mydata_Drosophila_melanogaster
%
% -------------------------------------------------------------------------
% ZERO-VARIATE DATA (scalar traits)
% -------------------------------------------------------------------------
%
% Embryo
%  - E0                : initial reserve per embryo (J) from embryogenesis energy budget
%
% Pre-adult development (timing)
%  - ab                : age at hatching (days AEL; PEDtracker, Canton-S)
%  - t1, t2            : times of 1st and 2nd larval molt after hatching
%  - tj / tp           : time since birth at pupation
%  - tD_m, tD_f        : sex-specific egg-to-adult development time (h)
%  - tD                : sex-mean egg-to-adult development time
%
% Pre-adult survivorship
%  - S_larva_*         : mean survivorship to larval stage (diet/strain specific)
%  - S_pupa_*          : mean survivorship to pupal stage
%  - S_adult_*         : mean survivorship to adult eclosion
%
% Adult lifespan (scalar summaries)
%  - am_f_*, am_m_* : time to 50% adult mortality, sex-specific
%  - am_*              : time to 50% adult mortality, sex-mean
%  - am_BD_DD, am_FD_DD   : mean adult lifespan (BD/FD; DD)
%  - am_BD_LD, am_FD_LD   : mean adult lifespan (BD/FD; LD)
%  - am_BD, am_FD         : photoperiod-merged mean lifespan per stock
%  - am_DD, am_LD         : stock-merged mean lifespan per photoperiod
%
% Morphology
%  - Larvae (diet/strain-specific):
%      Ww_larva_*, Dw_larva_* : wet and dry mass
%      L_larva_*,  W_larva_*  : body length and width
%  - Adults:
%      Lw_e_m_*, Lw_e_f_*   : wing length, sex-specific
%      Lw_e_*               : wing length, sex-mean
%      Ww_e_*            : adult wet mass (females)
%
% Reproduction
%  - Ri / R              : mean daily fecundity (eggs female^-1 day^-1)
%
% -------------------------------------------------------------------------
% UNI-VARIATE DATA (curves)
% -------------------------------------------------------------------------
%
% Growth
%  - tWw_f, tWw_m        : wet weight vs age, females and males
%  - tWw                : sex-merged wet weight vs age
%  - tWd_f, tWd_m        : dry weight vs age, females and males (Pacific strain)
%  - tWd                : sex-merged dry weight vs age
%
% Stress resistance (Yadav & Sharma 2014)
%  - Starvation survivorship (% vs h):
%      tS_FD_DD_m/f, tS_BD_DD_m/f : sex-specific, DD
%      tS_FD_LD_m/f, tS_BD_LD_m/f : sex-specific, LD
%      tS_FD_DD, tS_BD_DD         : sex-merged, DD
%      tS_FD_LD, tS_BD_LD         : sex-merged, LD
%      tS_FD, tS_BD               : photoperiod-merged
%      tS                         : stock-merged (BD+FD)
%
%  - Starvation + desiccation survivorship (% vs h):
%      analogous hierarchy of datasets:
%      sex-specific → sex-merged → photoperiod-merged → stock-merged
%      final merged dataset: tSC
%
% Adult survivorship curves
%  - tL_FD_DD, tL_BD_DD  : FD/BD, DD
%  - tL_FD_LD, tL_BD_LD  : FD/BD, LD
%  - tL_FD, tL_BD        : photoperiod-merged
%  - tL                  : stock-merged adult survivorship curve
%
% Diet-dependent adult performance (Ng'oma et al.)
%  - Adult survivorship vs age:
%      tS_C, tS_DR, tS_HS : control, dietary restriction, high sugar
%      tS_diets           : diet-mean survivorship
%  - Fecundity vs age:
%      tR_C, tR_DR, tR_HS : diet-specific fecundity curves
%      tR_diets           : diet-mean fecundity curve
%
% -------------------------------------------------------------------------
% Notes
%  - Raw condition-specific datasets are preserved alongside explicitly
%    merged datasets (sex-, photoperiod-, diet-, or stock-mean).
%  - Temperature is specified per dataset when differing from the default
%    metaData.T_typical = 25 °C.
%  - Data span the full life cycle (embryo → larva → pupa → adult) and
%    support integrated DEB parameter estimation.



%% Song et al. (2019) Curr Biol 29:R551–R567: D. melanogaster embryogenesis energy budget;
%  non-feeding embryo ⇒ initial reserve equals total mobilized energy; calorimetry/respirometry/biochemistry; total heat dissipated fertilization→hatching ≈ 10 mJ per embryo.

data.E0 = 1.0e-2; units.E0 = {'J'}; label.E0 = {'initial reserve','E_0 at fertilization'}; bibkey.E0 = {'Song2019'}; temp.E0 = C2K(25); units.temp.E0 = 'K'; label.temp.E0 = 'temperature';

%% Schumann I & Triphan T (2020) The PEDtracker: An automatic staging approach for Drosophila melanogaster larvae.
% Wild-type D. melanogaster (Canton-S). Husbandry: 25 °C, ~65% humidity, 14:10 h light:dark cycle. Tracking in climate chamber: 23–25 °C, 60–65% humidity, constant light during recording.

% Timing: hatch 0.7 d AEL; 1st molt 1.9 d AH; 2nd molt 3.5 d AH; pupation 7.8 d AH (Table 3)
data.ab = 0.7;      units.ab = 'd';     label.ab = 'age at birth';                          bibkey.ab = {'Schu2020'};   temp.ab = C2K(25);  units.temp.ab = 'K';    label.temp.ab = 'temperature';
data.t1 = 1.9;      units.t1 = 'd';     label.t1 = 'duration of instar 1';                  bibkey.t1 = {'Schu2020'};  temp.t1 = C2K(25);  units.temp.t1 = 'K';    label.temp.t1 = 'temperature';
data.t2 = 1.6;      units.t2 = 'd';     label.t2 = 'duration of instar 2';                  bibkey.t2 = {'Schu2020'};  temp.t2 = C2K(25);  units.temp.t2 = 'K';    label.temp.t2 = 'temperature';
data.tj = 7.8;      units.tj = 'd';     label.tj = 'time since birth at pupation';          bibkey.tj = {'Schu2020'};   temp.tj = C2K(25);  units.temp.tj = 'K';    label.temp.tj = 'temperature';

% Lengths: young L1 0.6 mm; late L1 1.3 mm; late L2 2.5 mm; late L3 3.8 mm (Table 4)
data.Lb = 0.06;     units.Lb = 'cm';    label.Lb = 'physical length of young instar 1';     bibkey.Lb = {'Schu2020'};
data.L1 = 0.13;     units.L1 = 'cm';    label.L1 = 'physical length at end of instar 1';    bibkey.L1 = {'Schu2020'};
data.L2 = 0.25;     units.L2 = 'cm';    label.L2 = 'physical length at end of instar 2';    bibkey.L2 = {'Schu2020'};
data.Lj = 0.38;     units.Lj = 'cm';    label.Lj = 'physical length of pupa';               bibkey.Lj = {'Schu2020'};

%% Bharathi et al. (2004) J Zool 264:87–95: D. melanogaster (JB-1 lab pop, >700 gens); 25°C, constant light, ~90% RH; banana–jaggery food; metrics digitized for D. melanogaster from Figs 1 (egg→eclosion dev time, h; m/f), 4 (larval & pupal survivorship; pre-adult=larval×pupal), 5 (dry wt at eclosion, g; m/f; axis 10^-3 g/fly), 6 (mean daily fecundity, eggs/d over first 10 d).

% data.ae_m = 234/24; 
data.ae_f = 232/24; 
