% data.Sl   = 0.82; data.Sp = 0.95; data.S = data.Sl*data.Sp;

% data.Wd_e_m = 0.27e-3; 
data.Wd_e_f = 0.35e-3; 
% data.Wd_e = 0.5*(data.Wd_e_m + data.Wd_e_f);

data.R    = 11.2;

% units.ae_m={'d'}; label.ae_m={'egg to eclosion development time','male'};   bibkey.ae_m={'Bha2004'}; temp.ae_m=C2K(25); units.temp.ae_m='K'; label.temp.ae_m='temperature';
units.ae_f={'d'}; label.ae_f={'egg to eclosion development time','female'}; bibkey.ae_f={'Bha2004'}; temp.ae_f=C2K(25); units.temp.ae_f='K'; label.temp.ae_f='temperature';
% units.ae  ={'d'}; label.ae  ={'egg to eclosion development time','sex-mean'}; bibkey.ae={'Bha2004'}; temp.ae=C2K(25); units.temp.ae='K'; label.temp.ae='temperature';

% units.Sl={'1'}; label.Sl={'mean survivorship','larval'};   bibkey.Sl={'Bha2004'}; temp.Sl=C2K(25); units.temp.Sl='K'; label.temp.Sl='temperature';
% units.Sp={'1'}; label.Sp={'mean survivorship','pupal'};    bibkey.Sp={'Bha2004'}; temp.Sp=C2K(25); units.temp.Sp='K'; label.temp.Sp='temperature';
% units.S ={'1'}; label.S ={'mean survivorship','pre-adult (larval×pupal)'}; bibkey.S={'Bha2004'}; temp.S=C2K(25); units.temp.S='K'; label.temp.S='temperature';

% units.Wd_e_m={'g'}; label.Wd_e_m={'dry weight at eclosion','male'};   bibkey.Wd_e_m={'Bha2004'}; temp.Wd_e_m=C2K(25); units.temp.Wd_e_m='K'; label.temp.Wd_e_m='temperature';
units.Wd_e_f={'g'}; label.Wd_e_f={'dry weight at eclosion','female'}; bibkey.Wd_e_f={'Bha2004'}; temp.Wd_e_f=C2K(25); units.temp.Wd_e_f='K'; label.temp.Wd_e_f='temperature';
% units.Wd_e  ={'g'}; label.Wd_e  ={'dry weight at eclosion','sex-mean'}; bibkey.Wd_e={'Bha2004'}; temp.Wd_e=C2K(25); units.temp.Wd_e='K'; label.temp.Wd_e='temperature';

units.R={'#/d'}; label.R={'mean daily fecundity (first 10 d)','eggs per female per day'}; bibkey.R={'Bha2004'}; temp.R=C2K(25); units.temp.R='K'; label.temp.R='temperature';

