% units.tWw_f  = {'d','mg'}; label.tWw_f  = {'time since hatching','wet weight (female)'};  bibkey.tWw_f  = {'ChRo1966'}; temp.tWw_f  = C2K(25); units.temp.tWw_f  = 'K'; label.temp.tWw_f  = 'temperature';

