% units.tWd_f= {'d','mg'}; label.tWd_f= {'time since hatching','dry weight (female)'};  bibkey.tWd_f= {'ChRo1966'}; temp.tWd_f= C2K(25); units.temp.tWd_f= 'K'; label.temp.tWd_f= 'temperature';
