   24 0.05; 36 0.20; 48 0.60; 60 1.40; 72 1.90; 84 1.70; 96 1.55; ...
  120 1.30; 144 1.28; 168 1.27; 192 1.25; 216 1.05 ];
data.tWw_f(:,1)=data.tWw_f(:,1)/24;

% --- Male
