units.tWw_f = {'d','mg'}; label.tWw_f = {'age since egg laying','body mass (female)'}; bibkey.tWw_f = {'Testa2013'}; temp.tWw_f = C2K(25); units.temp.tWw_f='K'; label.temp.tWw_f='temperature';
