units.tj_F424 = {'d'}; label.tj_F424 = {'time to 50% pupation','F424'}; bibkey.tj_F424 = {'Orme2017'}; temp.tj_F424 = C2K(21); units.temp.tj_F424 = 'K'; label.temp.tj_F424 = 'temperature';
units.tj_JAZZ = {'d'}; label.tj_JAZZ = {'time to 50% pupation','JAZZ'}; bibkey.tj_JAZZ = {'Orme2017'}; temp.tj_JAZZ = C2K(21); units.temp.tj_JAZZ = 'K'; label.temp.tj_JAZZ = 'temperature';

